I'll build a todo app that saves each item to the built-in database so they survive a refresh, with a clear empty state.

=== file: app.js ===
const list = document.getElementById('list');
const empty = document.getElementById('empty');
async function load() {
  const todos = await window.YIELD.entities.list('Todo');
  empty.classList.toggle('hidden', todos.length > 0);
  list.innerHTML = '';
  for (const t of todos) {
    const li = document.createElement('li');
    li.textContent = t.title;
    list.appendChild(li);
  }
}
document.getElementById('form').addEventListener('submit', async (e) => {
  e.preventDefault();
  const input = document.getElementById('input');
  if (!input.value.trim()) return;
  await window.YIELD.entities.create('Todo', { title: input.value.trim() });
  input.value = '';
  await load();
});
load();

I'll add a hero section with an AI-generated image.

=== file: app.js ===
async function loadHero() {
  const img = document.getElementById('hero');
  try {
    const url = await window.YIELD.image('a serene mountain landscape at sunrise, soft light, no text');
    img.src = url;
  } catch (e) { img.style.background = 'linear-gradient(135deg,#6366f1,#8b5cf6)'; }
}
loadHero();

I'll generate a 3D model and show it in an interactive viewer (Google's <model-viewer>).

=== file: index.html ===
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="utf-8"/>
<title>3D Viewer</title>
<script src="https://cdn.tailwindcss.com"></script>
<script type="module" src="https://ajax.googleapis.com/ajax/libs/model-viewer/3.5.0/model-viewer.min.js"></script>
</head>
<body class="min-h-screen bg-slate-900 flex items-center justify-center">
<model-viewer id="mv" camera-controls auto-rotate class="w-full h-screen" alt="3D model"></model-viewer>
<script src="app.js"></script>
</body>
</html>

=== file: app.js ===
async function load3d() {
  const mv = document.getElementById('mv');
  try {
    const url = await window.YIELD.model3d('a modern wooden chair, product render');
    mv.src = url;
  } catch (e) { console.error('3D failed', e); }
}
load3d();

I'll add a muted, looping AI-generated background video with a readable overlay.

=== file: app.js ===
async function loadVideo() {
  const v = document.getElementById('bg');
  try {
    v.src = await window.YIELD.video('slow aerial drone shot over ocean waves, cinematic');
    v.muted = true; v.loop = true; v.playsInline = true; v.play();
  } catch (e) { v.parentElement.style.background = '#0f172a'; }
}
loadVideo();

I'll create a Yield AI agent and wire a chat box to it.

=== agent: Helper ===
You are a helpful assistant embedded in the user's app. Answer briefly and clearly.

=== file: chat.js ===
const id = window.YIELD.agents['Helper'];
async function ask(text) {
  const res = await fetch('/api/agents/' + id + '/run', {
    method: 'POST', headers: { 'content-type': 'application/json' },
    body: JSON.stringify({ input: text })
  });
  const { output } = await res.json();
  return output;
}
